Javascript.isEnabled:
var val1 = Services.getValue(ListFiledWithCopyDocs.dataBinding);
var val2 = Services.getValue(IsWorkMaterialsFiledList.dataBinding);

return('Y' != val1 && 'Y' == val2);

Javascript.logic:
	var val1 = Services.getValue(ListFiledWithCopyDocs.dataBinding);
	var val2 = Services.getValue(IsWorkMaterialsFiledList.dataBinding);

	if('Y' == val1 || 'Y' != val2)
	{	Services.setValue(ListServedFiledDate2.dataBinding, "");
	}

Javascript.validate:
	//cannot be in past : working day only
	
	var checkDate = Services.getValue(ListServedFiledDate2.dataBinding); 
	var err = null;
	
	if( false == isFutureDate(checkDate))
	{ 	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInThePast_Msg");
	}
	else if( isNonWorkingDate(checkDate))
    {   err = ErrorCode.getErrorCode("CaseMan_dateNonWorkingDay_Msg"); 
    }
	
	return err;
